import{_ as e,c as a,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"OpenAI 额度: 查询 3 小时和 24 小时限额 | opencode-mystatus","description":"学习如何查询 OpenAI 的 3 小时和 24 小时限额。解读主窗口和次窗口信息，了解 Token 过期处理方法，掌握 Plus/Team/Pro 订阅额度差异。","frontmatter":{"title":"OpenAI 额度: 查询 3 小时和 24 小时限额 | opencode-mystatus","subtitle":"OpenAI 额度: 查询 3 小时和 24 小时限额","sidebarTitle":"OpenAI 额度","description":"学习如何查询 OpenAI 的 3 小时和 24 小时限额。解读主窗口和次窗口信息，了解 Token 过期处理方法，掌握 Plus/Team/Pro 订阅额度差异。","tags":["OpenAI","额度查询","API 配额"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"zh/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"zh/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),l={name:"zh/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function i(s,t,r,d,p,c){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="openai-额度查询-3-小时和-24-小时限额" tabindex="-1">OpenAI 额度查询：3 小时和 24 小时限额 <a class="header-anchor" href="#openai-额度查询-3-小时和-24-小时限额" aria-label="Permalink to &quot;OpenAI 额度查询：3 小时和 24 小时限额&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>使用 <code>/mystatus</code> 查询 OpenAI Plus/Team/Pro 订阅的额度</li><li>看懂输出中的 3 小时和 24 小时限额信息</li><li>理解主窗口和次窗口的区别</li><li>了解 Token 过期时的处理方式</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>OpenAI 的 API 调用有限额，超额后会被临时限制访问。但你不知道：</p><ul><li>当前还剩多少额度？</li><li>3 小时和 24 小时窗口哪个在用？</li><li>什么时候会重置？</li><li>为什么有时候看到两个窗口的数据？</li></ul><p>这些信息如果不及时掌握，可能影响你用 ChatGPT 写代码或做项目的进度。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>当你：</p><ul><li>需要频繁使用 OpenAI API 进行开发</li><li>发现响应变慢或被限流</li><li>想了解团队账号的使用情况</li><li>想知道什么时候额度会刷新</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>OpenAI 对 API 调用有两种限流窗口：</p><table tabindex="0"><thead><tr><th>窗口类型</th><th>时长</th><th>作用</th></tr></thead><tbody><tr><td><strong>主窗口</strong>（primary）</td><td>由 OpenAI 服务端返回</td><td>防止短时间内大量调用</td></tr><tr><td><strong>次窗口</strong>（secondary）</td><td>由 OpenAI 服务端返回（可能不存在）</td><td>防止长期超额使用</td></tr></tbody></table><p>mystatus 会并行查询这两个窗口，显示各自的：</p><ul><li>已使用百分比</li><li>剩余额度进度条</li><li>距离重置的时间</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>窗口时长由 OpenAI 服务端返回，不同订阅类型（Plus、Team、Pro）可能不同。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-执行查询命令" tabindex="-1">第 1 步：执行查询命令 <a class="header-anchor" href="#第-1-步-执行查询命令" aria-label="Permalink to &quot;第 1 步：执行查询命令&quot;">​</a></h3><p>在 OpenCode 中输入 <code>/mystatus</code>，系统会自动查询所有已配置平台的额度。</p><p><strong>你应该看到</strong>： 包含 OpenAI、智谱 AI、Z.ai、Copilot、Google Cloud 等平台的额度信息（取决于你配置了哪些平台）。</p><h3 id="第-2-步-找到-openai-部分" tabindex="-1">第 2 步：找到 OpenAI 部分 <a class="header-anchor" href="#第-2-步-找到-openai-部分" aria-label="Permalink to &quot;第 2 步：找到 OpenAI 部分&quot;">​</a></h3><p>在输出中找到 <code>## OpenAI Account Quota</code> 部分。</p><p><strong>你应该看到</strong>： 类似这样的内容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>████████████████░░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="第-3-步-解读主窗口信息" tabindex="-1">第 3 步：解读主窗口信息 <a class="header-anchor" href="#第-3-步-解读主窗口信息" aria-label="Permalink to &quot;第 3 步：解读主窗口信息&quot;">​</a></h3><p><strong>主窗口</strong>（primary_window）通常显示：</p><ul><li><strong>窗口名称</strong>：如 <code>3-hour limit</code> 或 <code>24-hour limit</code></li><li><strong>进度条</strong>：直观显示剩余额度的比例</li><li><strong>剩余百分比</strong>：如 <code>60% remaining</code></li><li><strong>重置时间</strong>：如 <code>Resets in: 2h 30m</code></li></ul><p><strong>你应该看到</strong>：</p><ul><li>窗口名称显示时长（3 小时 / 24 小时）</li><li>进度条越满代表剩余越多，越空代表越快用完</li><li>重置时间是倒计时，归零后额度会刷新</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>如果看到提示 <code>Limit reached!</code>，说明当前窗口额度已用完，需要等待重置。</p></div><h3 id="第-4-步-查看次窗口-如果有" tabindex="-1">第 4 步：查看次窗口（如果有） <a class="header-anchor" href="#第-4-步-查看次窗口-如果有" aria-label="Permalink to &quot;第 4 步：查看次窗口（如果有）&quot;">​</a></h3><p>如果 OpenAI 返回了次窗口数据，你会看到：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>█████████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>次窗口显示另一个时间维度的额度（通常是 24 小时）</li><li>可能与主窗口不同的剩余百分比</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>次窗口是独立的额度池，主窗口用完不影响次窗口，反之亦然。</p></div><h3 id="第-5-步-查看订阅类型" tabindex="-1">第 5 步：查看订阅类型 <a class="header-anchor" href="#第-5-步-查看订阅类型" aria-label="Permalink to &quot;第 5 步：查看订阅类型&quot;">​</a></h3><p>在 <code>Account</code> 行可以看到订阅类型：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                  ^^^^^</span></span>
<span class="line"><span>                                  订阅类型</span></span></code></pre></div><p><strong>常见的订阅类型</strong>：</p><ul><li><code>plus</code>：个人 Plus 订阅</li><li><code>team</code>：团队/组织订阅</li><li><code>pro</code>：Pro 订阅</li></ul><p><strong>你应该看到</strong>：</p><ul><li>你的账号类型显示在邮箱后的括号里</li><li>不同类型的限额可能不同</li></ul><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>验证一下你理解了：</p><table tabindex="0"><thead><tr><th>场景</th><th>你应该看到</th></tr></thead><tbody><tr><td>主窗口剩余 60%</td><td>进度条大约 60% 满，显示 <code>60% remaining</code></td></tr><tr><td>2.5 小时后重置</td><td>显示 <code>Resets in: 2h 30m</code></td></tr><tr><td>达到限额</td><td>显示 <code>Limit reached!</code></td></tr><tr><td>有次窗口</td><td>主窗口和次窗口各有一行数据</td></tr></tbody></table><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-错误操作-token-过期后不刷新" tabindex="-1">❌ 错误操作：Token 过期后不刷新 <a class="header-anchor" href="#❌-错误操作-token-过期后不刷新" aria-label="Permalink to &quot;❌ 错误操作：Token 过期后不刷新&quot;">​</a></h3><p><strong>错误现象</strong>：看到提示 <code>⚠️ OAuth 授权已过期</code>（中文）或 <code>⚠️ OAuth token expired</code>（英文）</p><p><strong>原因</strong>：OAuth Token 已过期（由服务端控制的具体时长），过期后无法查询额度。</p><p><strong>正确做法</strong>：</p><ol><li>在 OpenCode 中重新登录 OpenAI</li><li>Token 会自动刷新</li><li>再次执行 <code>/mystatus</code> 查询</li></ol><h3 id="❌-错误操作-混淆主窗口和次窗口" tabindex="-1">❌ 错误操作：混淆主窗口和次窗口 <a class="header-anchor" href="#❌-错误操作-混淆主窗口和次窗口" aria-label="Permalink to &quot;❌ 错误操作：混淆主窗口和次窗口&quot;">​</a></h3><p><strong>错误现象</strong>：以为只有一个窗口额度，结果主窗口用完次窗口还在用</p><p><strong>原因</strong>：两个窗口是独立的额度池。</p><p><strong>正确做法</strong>：</p><ul><li>关注两个窗口各自的重置时间</li><li>主窗口重置快，次窗口重置慢</li><li>合理分配使用，避免某个窗口长期超额</li></ul><h3 id="❌-错误操作-忽略团队账号-id" tabindex="-1">❌ 错误操作：忽略团队账号 ID <a class="header-anchor" href="#❌-错误操作-忽略团队账号-id" aria-label="Permalink to &quot;❌ 错误操作：忽略团队账号 ID&quot;">​</a></h3><p><strong>错误现象</strong>：Team 订阅显示的不是自己的使用情况</p><p><strong>原因</strong>：Team 订阅需要传递团队账号 ID，否则可能查询的是默认账号。</p><p><strong>正确做法</strong>：</p><ul><li>确保在 OpenCode 中登录了正确的团队账号</li><li>Token 中会自动包含 <code>chatgpt_account_id</code></li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>mystatus 通过调用 OpenAI 官方 API 查询额度：</p><ul><li>支持 OAuth 认证（Plus/Team/Pro）</li><li>显示主窗口和次窗口（如果存在）</li><li>进度条可视化剩余额度</li><li>倒计时显示重置时间</li><li>自动检测 Token 过期</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../zhipu-usage/">智谱 AI 和 Z.ai 额度查询</a></strong>。</p><p>你会学到：</p><ul><li>5 小时 Token 限额是什么</li><li>MCP 月度配额怎么查看</li><li>使用率超过 80% 时的警告提示</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>OpenAI 额度查询入口</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>OpenAI API 调用</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>格式化输出</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>JWT Token 解析</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>提取用户邮箱</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L78-L81" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>78-81</td></tr><tr><td>Token 过期检查</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>OpenAIAuthData 类型定义</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>常量</strong>：</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>：OpenAI 官方额度查询 API</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>queryOpenAIUsage(authData)</code>：查询 OpenAI 额度的主函数</li><li><code>fetchOpenAIUsage(accessToken)</code>：调用 OpenAI API</li><li><code>formatOpenAIUsage(data, email)</code>：格式化输出</li><li><code>parseJwt(token)</code>：解析 JWT Token（非标准库实现）</li><li><code>getEmailFromJwt(token)</code>：从 Token 提取用户邮箱</li><li><code>getAccountIdFromJwt(token)</code>：从 Token 提取团队账号 ID</li></ul></details>`,70)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
